# Strict allowlist of algorithms we actually support
ALLOWED_ALGORITHMS = frozenset({"HS256", "HS384", "HS512", "RS256", "RS384", "RS512", "ES256", "ES384", "ES512"})

# Algorithms that must NEVER be accepted
FORBIDDEN_ALGORITHMS = frozenset({"none", "None", "NONE", "nOnE"})

# Minimum key lengths for HMAC algorithms (in bytes)
MIN_HMAC_KEY_LENGTH = 32  # 256 bits minimum

# Algorithm-to-key-type mapping for validation
HMAC_ALGORITHMS = frozenset({"HS256", "HS384", "HS512"})
RSA_ALGORITHMS = frozenset({"RS256", "RS384", "RS512"})
EC_ALGORITHMS = frozenset({"ES256", "ES384", "ES512"})


class JWTConfig:
    """Configuration for JWT operations with security defaults."""

    def __init__(
        self,
        algorithm: str,
        secret_key: Optional[str] = None,
        private_key: Optional[str] = None,
        public_key: Optional[str] = None,
        issuer: Optional[str] = None,
        audience: Optional[str] = None,
        access_token_expires: int = 900,  # 15 minutes
        refresh_token_expires: int = 86400,  # 24 hours
        require_exp: bool = True,
        require_iat: bool = True,
        require_nbf: bool = False,
        require_iss: bool = True,
        require_aud: bool = True,
        require_jti: bool = True,
        leeway: int = 0,  # No leeway by default; set small value if clock skew is expected
        max_token_age: Optional[int] = None,
    ):
        self.algorithm = algorithm
        self.secret_key = secret_key
        self.private_key = private_key
        self.public_key = public_key
        self.issuer = issuer
        self.audience = audience
        self.access_token_expires = access_token_expires
        self.refresh_token_expires = refresh_token_expires
        self.require_exp = require_exp
        self.require_iat = require_iat
        self.require_nbf = require_nbf
        self.require_iss = require_iss
        self.require_aud = require_aud
        self.require_jti = require_jti
        self.leeway = leeway
        self.max_token_age = max_token_age

        self._validate_config()

    def _validate_config(self):
        """Validate configuration for security issues."""
        # Reject forbidden algorithms
        if self.algorithm.lower() in {a.lower() for a in FORBIDDEN_ALGORITHMS}:
            raise InvalidAlgorithmError(
                f"Algorithm '{self.algorithm}' is forbidden and must never be used."
            )

        # Only allow explicitly supported algorithms
        if self.algorithm not in ALLOWED_ALGORITHMS:
            raise InvalidAlgorithmError(
                f"Algorithm '{self.algorithm}' is not in the allowed list: {sorted(ALLOWED_ALGORITHMS)}"
            )

        # Validate HMAC key strength
        if self.algorithm in HMAC_ALGORITHMS:
            if not self.secret_key:
                raise JWTError(f"secret_key is required for {self.algorithm}")
            if len(self.secret_key.encode('utf-8')) < MIN_HMAC_KEY_LENGTH:
                raise JWTError(
                    f"secret_key must be at least {MIN_HMAC_KEY_LENGTH} bytes "
                    f"(got {len(self.secret_key.encode('utf-8'))} bytes). "
                    f"Use a cryptographically random key."
                )

        # Validate asymmetric key presence
        if self.algorithm in RSA_ALGORITHMS or self.algorithm in EC_ALGORITHMS:
            if not self.public_key:
                raise JWTError(f"public_key is required for {self.algorithm} verification")

        # Validate issuer and audience are set when required
        if self.require_iss and not self.issuer:
            raise JWTError("issuer must be set when require_iss is True")
        if self.require_aud and not self.audience:
            raise JWTError("audience must be set when require_aud is True")

        # Validate token expiration is reasonable
        if self.access_token_expires > 3600:
            import warnings
            warnings.warn(
                f"Access token expiration of {self.access_token_expires}s is longer than recommended (3600s).",
                UserWarning,
                stacklevel=3,
            )

        if self.leeway > 30:
            import warnings
            warnings.warn(
                f"Leeway of {self.leeway}s is larger than recommended (30s max).",
                UserWarning,
                stacklevel=3,
            )

    def get_signing_key(self) -> Union[str, bytes]:
        """Get the key used for signing tokens."""
        if self.algorithm in HMAC_ALGORITHMS:
            return self.secret_key
        if self.algorithm in RSA_ALGORITHMS or self.algorithm in EC_ALGORITHMS:
            if not self.private_key:
                raise JWTError(f"private_key is required for signing with {self.algorithm}")
            return self.private_key
        raise InvalidAlgorithmError(f"Unsupported algorithm: {self.algorithm}")

    def get_verification_key(self) -> Union[str, bytes]:
        """Get the key used for verifying tokens."""
        if self.algorithm in HMAC_ALGORITHMS:
            return self.secret_key
        if self.algorithm in RSA_ALGORITHMS or self.algorithm in EC_ALGORITHMS:
            return self.public_key
        raise InvalidAlgorithmError(f"Unsupported algorithm: {self.algorithm}")


class TokenBlacklist:
    """Simple in-memory token blacklist. Replace with Redis/DB in production."""

    def __init__(self):
        self._blacklisted: Dict[str, float] = {}

    def blacklist(self, jti: str, exp: float):
        """Add a token's JTI to the blacklist."""
        self._blacklisted[jti] = exp

    def is_blacklisted(self, jti: str) -> bool:
        """Check if a token's JTI is blacklisted."""
        return jti in self._blacklisted

    def cleanup(self):
        """Remove expired entries from the blacklist."""
        now = time.time()
        self._blacklisted = {
            jti: exp for jti, exp in self._blacklisted.items() if exp > now
        }


class JWTManager:
    """
    Secure JWT manager supporting multiple algorithms.

    Security features:
    - Strict algorithm allowlist (no 'none' algorithm)
    - Algorithm pinning per configuration (prevents algorithm confusion attacks)
    - Minimum HMAC key length enforcement
    - Required claims validation (exp, iat, iss, aud, jti)
    - Token blacklisting support (for logout/revocation)
    - Type claim to distinguish access vs refresh tokens
    - Maximum token age validation
    """

    def __init__(self, app: Optional[Flask] = None):
        self._configs: Dict[str, JWTConfig] = {}
        self._blacklist = TokenBlacklist()
        self._app = None

        if app is not None:
            self.init_app(app)

    def init_app(self, app: Flask):
        """Initialize with a Flask application."""
        self._app = app
        app.extensions['jwt_manager'] = self

        # Register error handlers
        @app.errorhandler(JWTError)
        def handle_jwt_error(error):
            return jsonify({"error": str(error)}), 401

    def register_config(self, name: str, config: JWTConfig):
        """Register a named JWT configuration."""
        self._configs[name] = config

    def get_config(self, name: str) -> JWTConfig:
        """Get a named JWT configuration."""
        if name not in self._configs:
            raise JWTError(f"No JWT configuration registered with name '{name}'")
        return self._configs[name]

    @property
    def blacklist(self) -> TokenBlacklist:
        return self._blacklist

    def create_access_token(
        self,
        config_name: str,
        subject: str,
        additional_claims: Optional[Dict[str, Any]] = None,
    ) -> str:
        """Create a signed access token."""
        return self._create_token(
            config_name=config_name,
            subject=subject,
            token_type="access",
            additional_claims=additional_claims,
        )

    def create_refresh_token(
        self,
        config_name: str,
        subject: str,
        additional_claims: Optional[Dict[str, Any]] = None,
    ) -> str:
        """Create a signed refresh token."""
        return self._create_token(
            config_name=config_name,
            subject=subject,
            token_type="refresh",
            additional_claims=additional_claims,
        )

    def _create_token(
        self,
        config_name: str,
        subject: str,
        token_type: str,
        additional_claims: Optional[Dict[str, Any]] = None,
    ) -> str:
        """Internal method to create a signed JWT token."""
        config = self.get_config(config_name)
        now = datetime.now(timezone.utc)

        if token_type == "refresh":
            expires_delta = timedelta(seconds=config.refresh_token_expires)
        else:
            expires_delta = timedelta(seconds=config.access_token_expires)

        # Generate a unique token ID for revocation support
        jti = self._generate_jti()

        payload = {
            "sub": subject,
            "iat": now,
            "nbf": now,
            "exp": now + expires_delta,
            "jti": jti,
            "type": token_type,
        }

        if config.issuer:
            payload["iss"] = config.issuer
        if config.audience:
            payload["aud"] = config.audience

        if additional_claims:
            # Prevent overwriting critical claims
            protected_claims = {"sub", "iat", "nbf", "exp", "jti", "type", "iss", "aud"}
            for key in additional_claims:
                if key in protected_claims:
                    raise JWTError(f"Cannot override protected claim '{key}'")
            payload.update(additional_claims)

        # Sign with the EXACT algorithm specified in config (algorithm pinning)
        token = pyjwt.encode(
            payload,
            config.get_signing_key(),
            algorithm=config.algorithm,
            headers={"alg": config.algorithm, "typ": "JWT"},
        )

        return token

    def verify_token(
        self,
        token: str,
        config_name: str,
        expected_type: Optional[str] = None,
    ) -> Dict[str, Any]:
        """
        Verify a JWT token and return its payload.

        Security measures:
        - Algorithm is pinned to the config's algorithm (prevents algorithm confusion)
        - All required claims are validated
        - Token blacklist is checked
        - Token type is validated if expected_type is provided
        """
        config = self.get_config(config_name)

        # CRITICAL: Only allow the EXACT algorithm from the config.
        # This prevents algorithm confusion/substitution attacks.
        # Never pass a list that includes algorithms the token shouldn't use.
        allowed_algorithms = [config.algorithm]

        # Build required claims list
        required_claims = ["sub"]
        options = {}

        if config.require_exp:
            required_claims.append("exp")
            options["require"] = required_claims
        if config.require_iat:
            required_claims.append("iat")
        if config.require_nbf:
            required_claims.append("nbf")
        if config.require_jti:
            required_claims.append("jti")

        options["require"] = required_claims

        # Decode kwargs
        decode_kwargs: Dict[str, Any] = {
            "algorithms": allowed_algorithms,  # Strict algorithm pinning
            "options": options,
            "leeway": timedelta(seconds=config.leeway),
        }

        if config.require_iss and config.issuer:
            decode_kwargs["issuer"] = config.issuer
        if config.require_aud and config.audience:
            decode_kwargs["audience"] = config.audience

        try:
            # First, peek at the header to detect algorithm mismatch attacks
            unverified_header = pyjwt.get_unverified_header(token)
            header_alg = unverified_header.get("alg", "")

            # Reject if the token's header algorithm doesn't match our expected algorithm
            if header_alg != config.algorithm:
                raise InvalidAlgorithmError(
                    f"Token algorithm '{header_alg}' does not match expected '{config.algorithm}'"
                )

            # Reject 'none' algorithm explicitly (defense in depth)
            if header_alg.lower() == "none":
                raise InvalidAlgorithmError("Algorithm 'none' is not allowed")

            payload = pyjwt.decode(
                token,
                config.get_verification_key(),
                **decode_kwargs,
            )

        except pyjwt.ExpiredSignatureError:
            raise TokenExpiredError("Token has expired")
        except pyjwt.InvalidAlgorithmError as e:
            raise InvalidAlgorithmError(f"Invalid algorithm: {e}")
        except pyjwt.InvalidAudienceError:
            raise InvalidTokenError("Invalid audience claim")
        except pyjwt.InvalidIssuerError:
            raise InvalidTokenError("Invalid issuer claim")
        except pyjwt.MissingRequiredClaimError as e:
            raise MissingClaimError(f"Missing required claim: {e}")
        except pyjwt.DecodeError as e:
            raise InvalidTokenError(f"Token decode error: {e}")
        except pyjwt.InvalidTokenError as e:
            raise InvalidTokenError(f"Invalid token: {e}")

        # Check token blacklist (revocation)
        jti = payload.get("jti")
        if jti and self._blacklist.is_blacklisted(jti):
            raise InvalidTokenError("Token has been revoked")

        # Validate token type if expected
        if expected_type is not None:
            token_type = payload.get("type")
            if token_type != expected_type:
                raise InvalidTokenError(
                    f"Expected token type '{expected_type}', got '{token_type}'"
                )

        # Validate max token age if configured
        if config.max_token_age is not None:
            iat = payload.get("iat")
            if iat is not None:
                token_age = time.time() - iat
                if token_age > config.max_token_age:
                    raise TokenExpiredError(
                        f"Token age ({token_age:.0f}s) exceeds maximum ({config.max_token_age}s)"
                    )

        return payload

    def revoke_token(self, token: str, config_name: str):
        """Revoke a token by adding its JTI to the blacklist."""
        # We still need to decode to get the jti and exp
        # Use verify_token to ensure the token is valid before revoking
        payload = self.verify_token(token, config_name)
        jti = payload.get("jti")
        exp = payload.get("exp", time.time() + 86400)
        if jti:
            self._blacklist.blacklist(jti, exp)

    @staticmethod
    def _generate_jti() -> str:
        """Generate a cryptographically random token ID."""
        import secrets
        return secrets.token_urlsafe(32)


def jwt_required(config_name: str, token_type: str = "access"):
    """
    Flask decorator to require a valid JWT token.

    Usage:
        @app.route('/protected')
        @jwt_required('internal')
        def protected():
            user = g.jwt_payload['sub']
            return jsonify({"user": user})
    """
    def decorator(fn):
        @functools.wraps(fn)
        def wrapper(*args, **kwargs):
            jwt_manager: JWTManager = current_app.extensions.get('jwt_manager')
            if jwt_manager is None:
                return jsonify({"error": "JWT manager not initialized"}), 500

            # Extract token from Authorization header
            auth_header = request.headers.get("Authorization", "")
            if not auth_header.startswith("Bearer "):
                return jsonify({"error": "Missing or invalid Authorization header"}), 401

            token = auth_header[7:].strip()
            if not token:
                return jsonify({"error": "Empty token"}), 401

            # Basic sanity check on token format (should have 3 parts)
            parts = token.split(".")
            if len(parts) != 3:
                return jsonify({"error": "Malformed token"}), 401

            try:
                payload = jwt_manager.verify_token(
                    token, config_name, expected_type=token_type
                )
                g.jwt_payload = payload
                g.jwt_token = token
                g.jwt_config_name = config_name
            except TokenExpiredError as e:
                return jsonify({"error": str(e)}), 401
            except (InvalidTokenError, InvalidAlgorithmError, MissingClaimError) as e:
                return jsonify({"error": str(e)}), 401
            except JWTError as e:
                return jsonify({"error": str(e)}), 401

            return fn(*args, **kwargs)
        return wrapper
    return decorator


# --- Helper to generate RSA keys for testing/setup ---

def generate_rsa_keypair(key_size: int = 2048) -> tuple:
    """Generate an RSA key pair. Returns (private_key_pem, public_key_pem)."""
    if key_size < 2048:
        raise ValueError("RSA key size must be at least 2048 bits")

    private_key = rsa.generate_private_key(
        public_exponent=65537,
        key_size=key_size,
    )
    private_pem = private_key.private_bytes(
        encoding=serialization.Encoding.PEM,
        format=serialization.PrivateFormat.PKCS8,
        encryption_algorithm=serialization.NoEncryption(),
    ).decode('utf-8')

    public_pem = private_key.public_key().public_bytes(
        encoding=serialization.Encoding.PEM,
        format=serialization.PublicFormat.SubjectPublicKeyInfo,
    ).decode('utf-8')

    return private_pem, public_pem


