def create_app() -> Flask:
    """Create an example Flask application demonstrating the JWT wrapper."""
    app = Flask(__name__)

    jwt_manager = JWTManager(app)

    # --- Configure HS256 for internal services ---
    # Use a strong, random secret key (at least 32 bytes)
    internal_secret = os.environ.get(
        "JWT_INTERNAL_SECRET",
        # Fallback for development only - in production, always use env var
        "this-is-a-development-secret-key-at-least-32-bytes-long!!"
    )

    internal_config = JWTConfig(
        algorithm="HS256",
        secret_key=internal_secret,
        issuer="internal-auth-service",
        audience="internal-services",
        access_token_expires=900,   # 15 minutes
        refresh_token_expires=3600, # 1 hour
        require_exp=True,
        require_iat=True,
        require_iss=True,
        require_aud=True,
        require_jti=True,
        leeway=5,  # 5 seconds leeway for clock skew
    )
    jwt_manager.register_config("internal", internal_config)

    # --- Configure RS256 for public APIs ---
    private_key_pem, public_key_pem = generate_rsa_keypair(2048)

    # In production, load these from secure storage (e.g., AWS Secrets Manager, Vault)
    public_config = JWTConfig(
        algorithm="RS256",
        private_key=private_key_pem,
        public_key=public_key_pem,
        issuer="public-auth-service",
        audience="public-api",
        access_token_expires=600,    # 10 minutes
        refresh_token_expires=86400, # 24 hours
        require_exp=True,
        require_iat=True,
        require_iss=True,
        require_aud=True,
        require_jti=True,
        leeway=10,
    )
    jwt_manager.register_config("public", public_config)

    # --- Routes ---

    @app.route("/auth/internal/login", methods=["POST"])
    def internal_login():
        """Simulate internal service authentication."""
        data = request.get_json() or {}
        service_id = data.get("service_id")
        service_secret = data.get("service_secret")

        # In production, validate against a service registry
        if not service_id or not service_secret:
            return jsonify({"error": "Missing credentials"}), 400

        access_token = jwt_manager.create_access_token(
            config_name="internal",
            subject=service_id,
            additional_claims={"roles": ["service"]},
        )
        refresh_token = jwt_manager.create_refresh_token(
            config_name="internal",
            subject=service_id,
        )

        return jsonify({
            "access_token": access_token,
            "refresh_token": refresh_token,
            "token_type": "Bearer",
            "expires_in": internal_config.access_token_expires,
        })

    @app.route("/auth/public/login", methods=["POST"])
    def public_login():
        """Simulate public API authentication."""
        data = request.get_json() or {}
        username = data.get("username")
        password = data.get("password")

        if not username or not password:
            return jsonify({"error": "Missing credentials"}), 400

        # In production, validate against user database
        access_token = jwt_manager.create_access_token(
            config_name="public",
            subject=username,
            additional_claims={"roles": ["user"], "email": f"{username}@example.com"},
        )
        refresh_token = jwt_manager.create_refresh_token(
            config_name="public",
            subject=username,
        )

        return jsonify({
            "access_token": access_token,
            "refresh_token": refresh_token,
            "token_type": "Bearer",
            "expires_in": public_config.access_token_expires,
        })

    @app.route("/internal/data")
    @jwt_required("internal", token_type="access")
    def internal_data():
        """Protected internal endpoint."""
        payload = g.jwt_payload
        return jsonify({
            "message": f"Hello, service {payload['sub']}!",
            "roles": payload.get("roles", []),
            "token_id": payload.get("jti"),
        })

    @app.route("/api/profile")
    @jwt_required("public", token_type="access")
    def public_profile():
        """Protected public API endpoint."""
        payload = g.jwt_payload
        return jsonify({
            "user": payload["sub"],
            "email": payload.get("email"),
            "roles": payload.get("roles", []),
        })

    @app.route("/auth/logout", methods=["POST"])
    @jwt_required("public", token_type="access")
    def logout():
        """Revoke the current token."""
        jwt_manager.revoke_token(g.jwt_token, g.jwt_config_name)
        return jsonify({"message": "Token revoked successfully"})

    @app.route("/auth/refresh", methods=["POST"])
    def refresh():
        """Refresh an access token using a refresh token."""
        auth_header = request.headers.get("Authorization", "")
        if not auth_header.startswith("Bearer "):
            return jsonify({"error": "Missing Authorization header"}), 401

        refresh_token = auth_header[7:].strip()
        config_name = request.args.get("config", "public")

        try:
            payload = jwt_manager.verify_token(
                refresh_token, config_name, expected_type="refresh"
            )
        except JWTError as e:
            return jsonify({"error": str(e)}), 401

        # Revoke the old refresh token (rotation)
        jwt_manager.revoke_token(refresh_token, config_name)

        # Issue new tokens
        new_access = jwt_manager.create_access_token(
            config_name=config_name,
            subject=payload["sub"],
            additional_claims={
                k: v for k, v in payload.items()
                if k not in {"sub", "iat", "nbf", "exp", "jti", "type", "iss", "aud"}
            },
        )
        new_refresh = jwt_manager.create_refresh_token(
            config_name=config_name,
            subject=payload["sub"],
        )

        return jsonify({
            "access_token": new_access,
            "refresh_token": new_refresh,
            "token_type": "Bearer",
        })

    @app.route("/health")
    def health():
        return jsonify({"status": "healthy"})

    return app


if __name__ == "__main__":
    app = create_app()
    # In production, use a proper WSGI server (gunicorn, uwsgi)
    # and enable HTTPS
    app.run(debug=False, host="127.0.0.1", port=5000)